static const float (*FBW_Trace(int w))[9]
{
	if (w == 0) return fbw_0;
	if (w == 1) return fbw_1;
	if (w == 2) return fbw_2;
	if (w == 3) return fbw_3;
	if (w == 4) return fbw_4;
	if (w == 5) return fbw_5;
	if (w == 6) return fbw_6;
	if (w == 7) return fbw_7;
	if (w == 8) return fbw_8;
	if (w == 9) return fbw_9;
	if (w == 10) return fbw_10;
	if (w == 11) return fbw_11;
	if (w == 12) return fbw_12;
	if (w == 13) return fbw_13;
	return (const float (*)[9]) 0;
}
static int FBW_Len(int w)
{
	if (w == 0) return 147;
	if (w == 1) return 147;
	if (w == 2) return 147;
	if (w == 3) return 147;
	if (w == 4) return 147;
	if (w == 5) return 147;
	if (w == 6) return 147;
	if (w == 7) return 147;
	if (w == 8) return 147;
	if (w == 9) return 147;
	if (w == 10) return 147;
	if (w == 11) return 147;
	if (w == 12) return 147;
	if (w == 13) return 147;
	return 0;
}

static int   fbw_idx[MAX_CLIENTS];     /* which recorded jump */
static int   fbw_phase[MAX_CLIENTS];   /* 0 walk, 1 replay, 2 pause */
static int   fbw_fi[MAX_CLIENTS];      /* replay frame index */
static int   fbw_timer[MAX_CLIENTS];
static int   fbw_init[MAX_CLIENTS];

static void FragBot_RJ(gedict_t *self)
{
	int slot = NUM_FOR_EDICT(self) - 1;
	int idx, n, og;
	const float (*tr)[9];

	if (slot < 0 || slot >= MAX_CLIENTS) return;
	if (!fbw_init[slot]) { fbw_idx[slot]=0; fbw_phase[slot]=0; fbw_fi[slot]=0; fbw_timer[slot]=0; fbw_init[slot]=1; }
	idx = fbw_idx[slot]; if (idx < 0 || idx >= FBW_N) idx = 0;
	tr = FBW_Trace(idx); n = FBW_Len(idx);
	if (!tr || n <= 0) return;
	og = (int) self->s.v.flags & FL_ONGROUND;

	if ((int) cvar("k_fb_rj_debug")) { static int dt[MAX_CLIENTS]; if (++dt[slot] >= 19) { dt[slot]=0;
		G_bprint(2, "RJW s%d ph%d og%d xyz %d %d %d\n", slot, fbw_phase[slot], og,
			(int)self->s.v.origin[0], (int)self->s.v.origin[1], (int)self->s.v.origin[2]); } }

	/* keep RL so the launch sound/visual is a rocket */
	self->s.v.items = ((int) self->s.v.items) | IT_ROCKET_LAUNCHER;
	if (self->s.v.ammo_rockets < 5) self->s.v.ammo_rockets = 50;
	if (self->s.v.health < 100) self->s.v.health = 200;
	self->s.v.weapon = IT_ROCKET_LAUNCHER;
	self->fb.firing = false; self->fb.jumping = false;
	VectorClear(self->fb.dir_move_);

	switch (fbw_phase[slot]) {
	case 0: { /* WALK to the recording's start (frame 0), on the ground */
		float tx = tr[0][0], ty = tr[0][1];
		float dx = tx - self->s.v.origin[0], dy = ty - self->s.v.origin[1];
		float d = sqrt(dx*dx + dy*dy);
		if (d <= FBW_ARRIVE && og) {           /* arrived + grounded -> start replay */
			fbw_phase[slot] = 1; fbw_fi[slot] = 0; fbw_timer[slot] = 0;
			break;
		}
		if (d > 1.0f) {                        /* steer/move toward the start */
			self->fb.dir_move_[0] = dx / d;
			self->fb.dir_move_[1] = dy / d;
			self->fb.dir_move_[2] = 0;
			self->fb.desired_angle[PITCH] = 0;
			self->fb.desired_angle[YAW] = atan2(dy, dx) * 180.0f / 3.14159265f;
			if (og && d > 250.0f) self->fb.jumping = true; /* hop to cover ground */
		}
		if (++fbw_timer[slot] > FBW_WALK_TIMEOUT) {  /* stuck -> snap to grounded start */
			vec3_t p; p[0]=tr[0][0]; p[1]=tr[0][1]; p[2]=tr[0][2];
			setorigin(self, PASSVEC3(p)); VectorClear(self->s.v.velocity);
			fbw_phase[slot] = 1; fbw_fi[slot] = 0; fbw_timer[slot] = 0;
		}
		break;
	}
	case 1: { /* REPLAY the recorded jump frame-by-frame (dense -> smooth) */
		int i = fbw_fi[slot];
		vec3_t p;
		if (i >= n) { fbw_phase[slot] = 2; fbw_timer[slot] = FBW_PAUSE; break; }
		p[0] = tr[i][0]; p[1] = tr[i][1]; p[2] = tr[i][2];
		setorigin(self, PASSVEC3(p));
		self->s.v.velocity[0] = tr[i][3];   /* recorded velocity -> correct run/jump anim + client interp */
		self->s.v.velocity[1] = tr[i][4];
		self->s.v.velocity[2] = tr[i][5];
		self->fb.desired_angle[PITCH] = tr[i][6];
		self->fb.desired_angle[YAW]   = tr[i][7];
		self->s.v.angles[0] = tr[i][6]; self->s.v.angles[1] = tr[i][7]; self->s.v.angles[2] = 0;
		if (tr[i][8] != 0.0f) sound(self, CHAN_WEAPON, "weapons/rocket1i.wav", 1, ATTN_NORM);
		fbw_fi[slot] = i + 1;
		break;
	}
	case 2: /* PAUSE then walk to the next recording */
		if (--fbw_timer[slot] <= 0) {
			fbw_idx[slot] = (idx + 1) % FBW_N;
			fbw_phase[slot] = 0; fbw_timer[slot] = 0;
		}
		break;
	}
}
/* ===== /FRAGBOT_BLOCK ===== */

/* ===== FRAGBOT_CALL ===== */
	if ((int) cvar("k_fb_fragbot_mode") == 33 && !ISDEAD(self))
	{
		FragBot_RJ(self);
	}
